import { Injectable, computed, signal } from '@angular/core';

interface Line { id: string; price: number; qty: number; }

@Injectable({ providedIn: 'root' })
export class CartStore {
  private readonly _lines = signal<Line[]>([]);
  readonly lines = this._lines.asReadonly();

  readonly count = computed(() => this._lines().reduce((s, l) => s + l.qty, 0));
  readonly subtotal = computed(() => this._lines().reduce((s, l) => s + l.price * l.qty, 0));
  readonly tax = computed(() => Math.round(this.subtotal() * 0.08 * 100) / 100);
  readonly total = computed(() => this.subtotal() + this.tax());

  add(line: Line) {
    this._lines.update(ls => {
      const i = ls.findIndex(l => l.id === line.id);
      if (i === -1) return [...ls, line];
      const copy = [...ls];
      copy[i] = { ...copy[i], qty: copy[i].qty + line.qty };
      return copy;
    });
  }

  remove(id: string) { this._lines.update(ls => ls.filter(l => l.id !== id)); }
}

