import { Component, signal, computed } from '@angular/core';
import { toSignal, toObservable } from '@angular/core/rxjs-interop';
import { debounceTime, distinctUntilChanged, switchMap, map, startWith, catchError, of } from 'rxjs';
import { SearchApi, Result } from './search.api';

@Component({
  selector: 'app-search',
  standalone: true,
  template: `
    <input (input)="query.set($any($event.target).value)" placeholder="Search..." />
    @if (state().loading) { <p>Loading...</p> }
    <ul>
      @for (r of state().results; track r.id) {
        <li>{{ r.title }}</li>
      } @empty { <li>No results</li> }
    </ul>
  `,
})
export class SearchComponent {
  query = signal('');

  private readonly stream = toObservable(this.query).pipe(
    debounceTime(300),
    distinctUntilChanged(),
    switchMap(q =>
      q.trim() === ''
        ? of({ loading: false, results: [] as Result[] })
        : this.api.search(q).pipe(
            map(results => ({ loading: false, results })),
            catchError(() => of({ loading: false, results: [] as Result[] })),
            startWith({ loading: true, results: [] as Result[] })
          )
    )
  );

  state = toSignal(this.stream, { initialValue: { loading: false, results: [] as Result[] } });

  constructor(private api: SearchApi) {}
}

import { signal, computed, Signal } from '@angular/core';

export function createStore<T extends object>(initial: T) {
  const _state = signal<T>(initial);
  const state = _state.asReadonly();

  function select<R>(projector: (s: T) => R): Signal<R> {
    return computed(() => projector(_state()));
  }

  function update(patch: Partial<T> | ((s: T) => Partial<T>)) {
    _state.update(s => {
      const delta = typeof patch === 'function' ? patch(s) : patch;
      return { ...s, ...delta }; // new reference => triggers reactivity
    });
  }

  return { state, select, update };
}

// --- Concrete store ---
interface Todo { id: string; title: string; done: boolean; }
interface TodoState { todos: Todo[]; }

export function createTodoStore() {
  const store = createStore<TodoState>({ todos: [] });

  const todos = store.select(s => s.todos);
  const remaining = computed(() => todos().filter(t => !t.done).length);

  function addTodo(title: string) {
    store.update(s => ({
      todos: [...s.todos, { id: crypto.randomUUID(), title, done: false }],
    }));
  }

  function toggle(id: string) {
    store.update(s => ({
      todos: s.todos.map(t => (t.id === id ? { ...t, done: !t.done } : t)),
    }));
  }

  return { todos, remaining, addTodo, toggle };
}

import { Component, signal, viewChild, ElementRef, effect, inject, DestroyRef } from '@angular/core';
import { FeedApi, Item } from './feed.api';

@Component({
  selector: 'app-feed',
  standalone: true,
  template: `
    @for (item of items(); track item.id) {
      <article>{{ item.text }}</article>
    }
    @if (loading()) { <p>Loading...</p> }
    <div #sentinel style="height:1px"></div>
  `,
})
export class FeedComponent {
  private api = inject(FeedApi);
  private destroyRef = inject(DestroyRef);

  items = signal<Item[]>([]);
  private page = signal(0);
  loading = signal(false);
  private done = signal(false);

  sentinel = viewChild.required<ElementRef<HTMLElement>>('sentinel');

  constructor() {
    effect((onCleanup) => {
      const el = this.sentinel().nativeElement;
      const io = new IntersectionObserver(entries => {
        if (entries[0].isIntersecting) this.loadNext();
      });
      io.observe(el);
      onCleanup(() => io.disconnect());
    });
  }

  private loadNext() {
    if (this.loading() || this.done()) return; // guard against overlap
    this.loading.set(true);
    const next = this.page() + 1;
    this.api.getPage(next).subscribe({
      next: batch => {
        this.items.update(list => [...list, ...batch]);
        this.page.set(next);
        if (batch.length === 0) this.done.set(true);
        this.loading.set(false);
      },
      error: () => this.loading.set(false),
    });
  }
}

import { Component, inject } from '@angular/core';
import { NonNullableFormBuilder, FormArray, FormControl, FormGroup, Validators, AbstractControl, ValidationErrors, AsyncValidatorFn, ReactiveFormsModule } from '@angular/forms';
import { Observable, of, timer } from 'rxjs';
import { switchMap, map, catchError } from 'rxjs';
import { UserApi } from './user.api';

function passwordsMatch(group: AbstractControl): ValidationErrors | null {
  const pw = group.get('password')?.value;
  const confirm = group.get('confirmPassword')?.value;
  return pw === confirm ? null : { mismatch: true };
}

function usernameAvailable(api: UserApi): AsyncValidatorFn {
  return (control: AbstractControl): Observable<ValidationErrors | null> =>
    timer(300).pipe(
      switchMap(() => api.isTaken(control.value)),
      map(taken => (taken ? { taken: true } : null)),
      catchError(() => of(null))
    );
}

@Component({
  selector: 'app-signup',
  standalone: true,
  imports: [ReactiveFormsModule],
  template: `
    <form [formGroup]="form" (ngSubmit)="submit()">
      <input formControlName="username" placeholder="username" />
      @if (form.controls.username.pending) { <small>checking...</small> }
      @if (form.controls.username.hasError('taken')) { <small>taken</small> }

      <input formControlName="email" placeholder="email" />
      <input type="password" formControlName="password" />
      <input type="password" formControlName="confirmPassword" />
      @if (form.hasError('mismatch')) { <small>passwords differ</small> }

      <div formArrayName="hobbies">
        @for (ctrl of hobbies.controls; track $index) {
          <input [formControlName]="$index" placeholder="hobby" />
          <button type="button" (click)="removeHobby($index)">x</button>
        }
      </div>
      <button type="button" (click)="addHobby()">+ hobby</button>

      <button type="submit" [disabled]="form.invalid || form.pending">Sign up</button>
    </form>
  `,
})
export class SignupComponent {
  private fb = inject(NonNullableFormBuilder);
  private api = inject(UserApi);

  form = this.fb.group(
    {
      username: this.fb.control('', {
        validators: [Validators.required, Validators.minLength(3)],
        asyncValidators: [usernameAvailable(this.api)],
      }),
      email: this.fb.control('', [Validators.required, Validators.email]),
      password: this.fb.control('', [Validators.required, Validators.minLength(8)]),
      confirmPassword: this.fb.control('', [Validators.required]),
      hobbies: this.fb.array<FormControl<string>>([]),
    },
    { validators: passwordsMatch }
  );

  get hobbies(): FormArray<FormControl<string>> {
    return this.form.controls.hobbies;
  }

  addHobby() { this.hobbies.push(this.fb.control('')); }
  removeHobby(i: number) { this.hobbies.removeAt(i); }

  submit() {
    if (this.form.invalid) return;
    const value = this.form.getRawValue(); // fully typed, non-nullable
    this.api.signup(value).subscribe();
  }
}

