import { ApplicationConfig, inject } from '@angular/core';
import { provideRouter, withComponentInputBinding, Routes, CanMatchFn, ResolveFn } from '@angular/router';
import { FeatureFlags } from './feature-flags';
import { ReportApi, Report } from './report.api';

const reportsEnabled: CanMatchFn = () => inject(FeatureFlags).isOn('reports');

const resolveReport: ResolveFn<Report> = (route) =>
  inject(ReportApi).getById(route.paramMap.get('id')!);

export const routes: Routes = [
  {
    path: 'reports',
    canMatch: [reportsEnabled],
    loadChildren: () => import('./reports/reports.routes').then(m => m.REPORTS_ROUTES),
  },
  // Fallback taken when the flag is off, because CanMatch skipped the lazy route
  { path: 'reports', loadComponent: () => import('./reports/reports-disabled.component').then(m => m.ReportsDisabledComponent) },
];

// reports/reports.routes.ts
export const REPORTS_ROUTES: Routes = [
  {
    path: ':id',
    resolve: { report: resolveReport },
    loadComponent: () => import('./report-detail.component').then(m => m.ReportDetailComponent),
  },
];

// bootstrap
export const appConfig: ApplicationConfig = {
  providers: [provideRouter(routes, withComponentInputBinding())],
};

